#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int *A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &A[i]);
        int oddCnt = 0, ans = 0;
        for (int i = 0; i < K; ++i) if (A[i] & 1) ++oddCnt;
        if (oddCnt) ++ans;
        for (int i = K; i < N; ++i) {
            if (A[i - K] & 1) --oddCnt;
            if (A[i] & 1) ++oddCnt;
            if (oddCnt) ++ans;
        }
        printf("%d\n", ans);
        free(A);
    }
    return 0;
}

