import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        odd_cnt = sum(1 for x in A[:K] if x & 1)
        ans = 1 if odd_cnt else 0
        for i in range(K, N):
            if A[i - K] & 1:
                odd_cnt -= 1
            if A[i] & 1:
                odd_cnt += 1
            if odd_cnt:
                ans += 1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

